from beeai_framework import Agent
from pydantic import BaseModel

class ConsistentToolAgent(Agent):
    def __init__(self):
        super().__init__()
        self.response_format = {
            'type': 'json_object',
            'schema': {
                'type': 'object',
                'properties': {
                    'tool_calls': {'type': 'array'},
                    'content': {'type': 'string'}
                }
            }
        }

    async def _format_response(self, granite_response):
        return json.dumps({
            'tool_calls': granite_response.get('tool_calls', []),
            'content': granite_response.get('content', '')
        }, ensure_ascii=False)

from beeai_framework import Tool
from pydantic import BaseModel, validator

class SafeCalculatorTool(Tool):
    class Input(BaseModel):
        expression: str

        @validator('expression')
        def prevent_injection(cls, v):
            if any(x in v for x in [';', 'os.', 'import', '__']):
                raise ValueError('Injection detected')
            return v

    async def execute(self, input_data: Input):
        # Safe execution
        return eval(input_data.expression, {'__builtins__': {}})
